INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00270', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲為乙女分娩所生，從乙姓。嗣後甲經生父丙認領，乙丙約定變更為甲從丙姓。下列敘述何者 錯誤？', '["乙丙之約定，應以書面為之", "甲成年後，得變更為從乙姓，但以一次為限", "如甲被丁合法收養，甲不得維持從丙姓", "如甲被丁合法收養後從丁姓，自終止收養時起，甲回復為從丙姓"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00271', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲乙為夫妻，育有一子丙與一女丁，丙與戊女結婚，育有一子己。某日，甲丙因意外同時死亡， 下列敘述何者正確？', '["乙得繼承丙之遺產", "丁得繼承丙之遺產", "戊得繼承甲之遺產", "己得繼承甲之遺產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00272', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '被繼承人甲，中年喪偶，甲有一子A。A妻為B、AB生二子C、D。甲父為E。甲弟為F。下列 敘述何者正確？', '["甲如立有遺囑，遺贈新臺幣200萬元於F，F應於甲死亡後3個月內，以書面表示接受，逾期 未表示者，視為拋棄該項遺贈", "甲死亡後，A依法拋棄繼承，甲之繼承人為E", "甲死亡後，A依法拋棄繼承，甲之繼承人為C與D", "甲之繼承人係屬依法應書面通知因其拋棄而為繼承之人，如未通知者，繼承之拋棄為無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00273', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依司法院大法官解釋意旨，關於大學教師之升等評審程序，下列敘述何者正確？', '["基於大學自治，有關大學教師升等資格之審查，立法者不得為任何規定", "基於大學自治，對於升等決定不服之教師，不得提起行政訴訟", "大學教師升等資格之審查，涉及工作權之保障", "教師升等資格評審程序之目的在於維持學術研究與教學之品質，不受教育主管機關監督"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00274', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '有關監察權之行使，下列敘述何者錯誤？', '["監察院僅得對行政院及其有關部會提出糾正案", "監察委員對行政院及各部會行使之調查權範圍，僅限於調閱文件", "監察院院長對於彈劾案不得指使與干涉", "監察院院長對於糾舉案不得指使與干涉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00275', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '下列何者並非司法院釋字第499號解釋所列舉之修憲界限？', '["憲法第1條所樹立之民主共和國原則", "憲法第2條之國民主權原則", "憲法第2章所保障之各項人民基本權利", "憲法第13章所明定之基本國策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00276', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依憲法增修條文第10條第8項規定，國家就社會救助和國民就業，應優先編列下列何種支出？', '["一般性支出", "資本性支出", "救濟性支出", "政策性支出"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00277', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依憲法第8條第1項之規定，司法或警察機關依法定程序，得逮捕拘禁人民。關於本項規定之司法機關與警 察機關，下列敘述何者正確？', '["司法機關包括檢察機關，警察機關不限於組織法上之形式意義警察機關", "司法機關包括檢察機關，警察機關限於組織法上之形式意義警察機關", "司法機關不包括檢察機關，警察機關不限於組織法上之形式意義警察機關", "司法機關不包括檢察機關，警察機關限於組織法上之形式意義警察機關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00278', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '有關憲法第7條平等原則之敘述，下列何者正確？', '["平等原則禁止所有法律上的差別待遇", "優惠性差別待遇亦為平等原則所禁止", "基於平等原則，立法者應貫徹體系正義的要求", "平等原則僅拘束立法者，不拘束行政機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00279', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依司法院大法官解釋，下列何者違反憲法第13條保障之宗教信仰自由？', '["總統接見宗教領袖", "總統以私人名義參加宗教活動", "設立國教", "核准宗教團體設立學校"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
